3: define('categorySelector', [
4: 	'categorySearch', 'bootbox', 'hooks', 'translator',
5: ], function (categorySearch, bootbox, hooks, translator) {
6: 	const categorySelector = {};
7: 
8: 	categorySelector.init = function (el, options) {
9: 		if (!el || !el.length) {
10: 			return;
11: 		}
12: 		options = options || {};
13: 		const onSelect = options.onSelect || function () {};
14: 
15: 		options.states = options.states || ['watching', 'tracking', 'notwatching', 'ignoring'];
16: 		options.template = options.template || 'partials/category/selector-dropdown-left';
17: 		hooks.fire('action:category.selector.options', { el: el, options: options });
18: 
19: 		categorySearch.init(el, options);
20: 
21: 		const selector = {
22: 			el: el,
23: 			selectedCategory: null,
24: 		};
25: 
26: 		el.on('click', '[data-cid]', function () {
27: 			const categoryEl = $(this);
28: 			if (categoryEl.hasClass('disabled')) {
29: 				return false;
30: 			}
31: 			selector.selectCategory(categoryEl.attr('data-cid'));
32: 			return onSelect(selector.selectedCategory);
33: 		});
34: 
35: 		let defaultSelectHtml = selector.el.find('[component="category-selector-selected"]').html();
36: 
37: 		translator.translate(defaultSelectHtml, (translated) => {
38: 			defaultSelectHtml = translated;
39: 		});
40: 		selector.selectCategory = function (cid) {
41: 			const categoryEl = selector.el.find('[data-cid="' + cid + '"]');
42: 			selector.selectedCategory = {
43: 				cid: cid,
44: 				name: categoryEl.attr('data-name'),
45: 			};
46: 
47: 			if (categoryEl.length) {
48: 				selector.el.find('[component="category-selector-selected"]').html(
49: 					categoryEl.find('[component="category-markup"]').html()
50: 				);
51: 			} else {
52: 				selector.el.find('[component="category-selector-selected"]').html(
53: 					defaultSelectHtml
54: 				);
55: 			}
56: 		};
57: 		selector.getSelectedCategory = function () {
58: 			return selector.selectedCategory;
59: 		};
60: 		selector.getSelectedCid = function () {
61: 			return selector.selectedCategory ? selector.selectedCategory.cid : 0;
62: 		};
63: 
64: 		if (options.hasOwnProperty('selectedCategory')) {
65: 			app.parseAndTranslate(options.template, { selectedCategory: options.selectedCategory }, function (html) {
66: 				selector.el.find('[component="category-selector-selected"]').html(
67: 					html.find('[component="category-selector-selected"]').html()
68: 				);
69: 			});
70: 		}
71: 		return selector;
72: 	};
73: 
