149: 		function changeWatching(type, state = 1) {
150: 			const method = state ? 'put' : 'del';
151: 			api[method](`/topics/${tid}/${type}`, {}, () => {
152: 				let message = '';
153: 				if (type === 'follow') {
154: 					message = state ? '[[topic:following-topic.message]]' : '[[topic:not-following-topic.message]]';
155: 				} else if (type === 'ignore') {
156: 					message = state ? '[[topic:ignoring-topic.message]]' : '[[topic:not-following-topic.message]]';
157: 				}
158: 
159: 				// From here on out, type changes to 'unfollow' if state is falsy
160: 				if (!state) {
161: 					type = 'unfollow';
162: 				}
163: 
164: 				setFollowState(type);
165: 
166: 				alerts.alert({
167: 					alert_id: 'follow_thread',
168: 					message: message,
169: 					type: 'success',
170: 					timeout: 5000,
171: 				});
172: 
173: 				hooks.fire('action:topics.changeWatching', { tid: tid, type: type });
174: 			}, () => {
175: 				alerts.alert({
176: 					type: 'danger',
177: 					alert_id: 'topic_follow',
178: 					title: '[[global:please-log-in]]',
179: 					message: '[[topic:login-to-subscribe]]',
180: 					timeout: 5000,
181: 				});
182: 			});
183: 
184: 			return false;
185: 		}
186: 	};
