188: 	ThreadTools.observeTopicLabels = function (labels) {
189: 		// show or hide topic/labels container depending on children visibility
190: 		const mut = new MutationObserver(function (mutations) {
191: 			const first = mutations[0];
192: 			if (first && first.attributeName === 'class') {
193: 				const visibleChildren = labels.children().filter((index, el) => !$(el).hasClass('hidden'));
194: 				labels.toggleClass('hidden', !visibleChildren.length);
195: 			}
196: 		});
197: 
198: 		labels.children().each((index, el) => {
199: 			mut.observe(el, { attributes: true });
200: 		});
201: 	};
202: 
203: 	function renderMenu(container) {
204: 		if (!container) {
205: 			return;
206: 		}
207: 		container.on('show.bs.dropdown', '.thread-tools', async function () {
208: 			const $this = $(this);
209: 			const dropdownMenu = $this.find('.dropdown-menu');
210: 			const { top } = this.getBoundingClientRect();
211: 			$this.toggleClass('dropup', top > window.innerHeight / 2);
212: 			if (dropdownMenu.attr('data-loaded')) {
213: 				return;
214: 			}
215: 			dropdownMenu.html(helpers.generatePlaceholderWave([8, 8, 8]));
216: 			const data = await socket.emit('topics.loadTopicTools', { tid: ajaxify.data.tid, cid: ajaxify.data.cid });
217: 			const html = await app.parseAndTranslate('partials/topic/topic-menu-list', data);
218: 			$(dropdownMenu).attr('data-loaded', 'true').html(html);
219: 			hooks.fire('action:topic.tools.load', {
220: 				element: $(dropdownMenu),
221: 			});
222: 		});
223: 	}
